@tailwind base;
@tailwind components;
@tailwind utilities;

/* Design Tokens */
:root {
  /* Typography Scale - Desktop */
  --text-h1: 48px;
  --text-h1-line: 56px;
  --text-h2: 36px;
  --text-h2-line: 44px;
  --text-h3: 24px;
  --text-h3-line: 32px;
  --text-body: 16px;
  --text-body-line: 24px;
  --text-small: 14px;
  --text-small-line: 20px;

  /* Letter Spacing */
  --tracking-tight: -0.02em;
  --tracking-normal: 0;
  --tracking-wide: 0.05em;

  /* Gradients */
  --gradient-holographic: linear-gradient(135deg, #00D4FF 0%, #00F0FF 50%, #0A0E17 100%);
  --gradient-arc-reactor: radial-gradient(circle, #00D4FF 0%, #FF6B00 100%);
  --gradient-playful: linear-gradient(135deg, #FF6B9D 0%, #B794F6 100%);
}

/* Mobile Typography */
@media (max-width: 768px) {
  :root {
    --text-h1: 32px;
    --text-h1-line: 40px;
    --text-h2: 28px;
    --text-h2-line: 36px;
    --text-h3: 20px;
    --text-h3-line: 28px;
  }
}

/* Base Styles */
body {
  background-color: #0A0E17;
  color: #E8F4F8;
  font-family: var(--font-body);
  font-size: var(--text-body);
  line-height: var(--text-body-line);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  font-weight: 700;
  line-height: 1.2;
  letter-spacing: var(--tracking-tight);
}

h1 {
  font-size: var(--text-h1);
  line-height: var(--text-h1-line);
}

h2 {
  font-size: var(--text-h2);
  line-height: var(--text-h2-line);
}

h3 {
  font-size: var(--text-h3);
  line-height: var(--text-h3-line);
}

code,
pre,
.mono {
  font-family: var(--font-mono);
  font-size: var(--text-small);
  letter-spacing: var(--tracking-wide);
}

/* Reduced Motion */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .particle-system {
    display: none;
  }

  .holographic-element {
    animation: none !important;
  }
}

/* Utility Classes */
.text-gradient-holographic {
  background: var(--gradient-holographic);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-gradient-playful {
  background: var(--gradient-playful);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.glow-holographic {
  box-shadow: 0 0 20px rgba(0, 212, 255, 0.5);
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 10px;
}

::-webkit-scrollbar-track {
  background: #0A0E17;
}

::-webkit-scrollbar-thumb {
  background: #00D4FF;
  border-radius: 5px;
}

::-webkit-scrollbar-thumb:hover {
  background: #00F0FF;
}

