import {
  measureFrameTime,
  shouldReEnableParticles,
  getMemoryUsage,
  isMemoryBudgetExceeded,
  getPerformanceMetrics,
  resetPerformanceMonitoring,
} from '../performance';

describe('performance', () => {
  beforeEach(() => {
    resetPerformanceMonitoring();
  });

  describe('measureFrameTime', () => {
    it('does not disable particles for fast frames', () => {
      const delta = 0.01; // 10ms - fast
      const result = measureFrameTime(delta);

      expect(result.shouldDisableParticles).toBe(false);
    });

    it('disables particles after 3 consecutive slow frames', () => {
      const slowDelta = 0.025; // 25ms - above threshold

      measureFrameTime(slowDelta);
      measureFrameTime(slowDelta);
      const result = measureFrameTime(slowDelta);

      expect(result.shouldDisableParticles).toBe(true);
    });

    it('resets slow frame count after a fast frame', () => {
      const slowDelta = 0.025;
      const fastDelta = 0.01;

      measureFrameTime(slowDelta);
      measureFrameTime(slowDelta);
      measureFrameTime(fastDelta); // Resets count
      const result = measureFrameTime(slowDelta);

      expect(result.shouldDisableParticles).toBe(false);
    });
  });

  describe('shouldReEnableParticles', () => {
    it('returns true when particles were never disabled', () => {
      expect(shouldReEnableParticles()).toBe(true);
    });

    it('returns false immediately after disabling', () => {
      measureFrameTime(0.025);
      measureFrameTime(0.025);
      measureFrameTime(0.025);

      expect(shouldReEnableParticles()).toBe(false);
    });
  });

  describe('getMemoryUsage', () => {
    it('returns memory usage in MB when API is available', () => {
      const mockMemory = {
        usedJSHeapSize: 50 * 1024 * 1024, // 50MB
      };
      (performance as any).memory = mockMemory;

      const usage = getMemoryUsage();
      expect(usage).toBe(50);
    });

    it('returns 0 when API is not available', () => {
      (performance as any).memory = undefined;

      const usage = getMemoryUsage();
      expect(usage).toBe(0);
    });
  });

  describe('isMemoryBudgetExceeded', () => {
    it('returns true when memory usage exceeds 100MB', () => {
      const mockMemory = {
        usedJSHeapSize: 101 * 1024 * 1024, // 101MB
      };
      (performance as any).memory = mockMemory;

      expect(isMemoryBudgetExceeded()).toBe(true);
    });

    it('returns false when memory usage is under 100MB', () => {
      const mockMemory = {
        usedJSHeapSize: 50 * 1024 * 1024, // 50MB
      };
      (performance as any).memory = mockMemory;

      expect(isMemoryBudgetExceeded()).toBe(false);
    });
  });

  describe('getPerformanceMetrics', () => {
    it('returns comprehensive metrics', () => {
      const delta = 0.016; // ~60fps
      const metrics = getPerformanceMetrics(delta);

      expect(metrics).toHaveProperty('frameTime');
      expect(metrics).toHaveProperty('fps');
      expect(metrics).toHaveProperty('memoryUsed');
      expect(metrics).toHaveProperty('shouldDisableParticles');
      expect(metrics.fps).toBeCloseTo(62.5, 0);
    });
  });
});

