import { validateBlogFrontmatter, validateBlogFrontmatterSafe } from '../blogSchema';
import { ZodError } from 'zod';

describe('blogSchema', () => {
  const validFrontmatter = {
    title: 'My Blog Post',
    date: '2024-03-15',
    tags: ['GraphQL', 'React'],
    excerpt: 'A post about GraphQL',
    featured: false,
  };

  describe('validateBlogFrontmatter', () => {
    it('accepts valid frontmatter', () => {
      const result = validateBlogFrontmatter(validFrontmatter);

      expect(result).toEqual(validFrontmatter);
    });

    it('throws ZodError for missing title', () => {
      const invalid = { ...validFrontmatter, title: '' };

      expect(() => validateBlogFrontmatter(invalid)).toThrow(ZodError);
    });

    it('throws ZodError for invalid date format', () => {
      const invalid = { ...validFrontmatter, date: '2024/03/15' };

      expect(() => validateBlogFrontmatter(invalid)).toThrow(ZodError);
    });

    it('throws ZodError for empty tags array', () => {
      const invalid = { ...validFrontmatter, tags: [] };

      expect(() => validateBlogFrontmatter(invalid)).toThrow(ZodError);
    });

    it('throws ZodError for title too long (>200 chars)', () => {
      const invalid = {
        ...validFrontmatter,
        title: 'a'.repeat(201),
      };

      expect(() => validateBlogFrontmatter(invalid)).toThrow(ZodError);
    });

    it('throws ZodError for excerpt too long (>500 chars)', () => {
      const invalid = {
        ...validFrontmatter,
        excerpt: 'a'.repeat(501),
      };

      expect(() => validateBlogFrontmatter(invalid)).toThrow(ZodError);
    });

    it('defaults featured to false when not provided', () => {
      const withoutFeatured = {
        title: 'Test',
        date: '2024-03-15',
        tags: ['test'],
        excerpt: 'Test excerpt',
      };

      const result = validateBlogFrontmatter(withoutFeatured);

      expect(result.featured).toBe(false);
    });
  });

  describe('validateBlogFrontmatterSafe', () => {
    it('returns success for valid frontmatter', () => {
      const result = validateBlogFrontmatterSafe(validFrontmatter);

      expect(result.success).toBe(true);
    });

    it('returns error for invalid frontmatter', () => {
      const invalid = { ...validFrontmatter, title: '' };
      const result = validateBlogFrontmatterSafe(invalid);

      expect(result.success).toBe(false);
    });
  });
});

