            <button
              onClick={() => {
                setShowModal(false);
                window.location.href = '#projects';
              }}
              className="mt-6 w-full px-6 py-3 bg-gradient-playful text-white font-heading font-bold rounded-lg hover:opacity-90 transition-opacity"
            >
              Want more detail?
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

interface HeroProps {
  isWebGLSupported: boolean;
}

export default function Hero({ isWebGLSupported }: HeroProps) {
  if (isWebGLSupported) {
    return <DesktopHero />;
  }

  return <MobileHero />;
