import { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { ShaderMaterial, PlaneGeometry, Mesh } from 'three';

/**
 * Scanline shader component
 * Creates horizontal holographic scanlines with subtle vertical drift
 */
export default function Scanlines() {
  const materialRef = useRef<ShaderMaterial>(null);

  const vertexShader = `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `;

  const fragmentShader = `
    uniform float uTime;
    varying vec2 vUv;

    void main() {
      // Horizontal scanlines
      float scanline = sin(vUv.y * 800.0) * 0.04;

      // Subtle vertical drift
      float drift = sin(uTime * 0.5) * 0.002;

      // Holographic blue color
      vec3 color = vec3(0.0, 0.83, 1.0);

      gl_FragColor = vec4(color, 0.1 + scanline + drift);
    }
  `;

  useFrame(({ clock }) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = clock.getElapsedTime();
    }
  });

  return (
    <mesh position={[0, 0, -1]}>
      <planeGeometry args={[20, 20]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={{ uTime: { value: 0 } }}
        transparent
        depthWrite={false}
      />
    </mesh>
  );
}

