import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { BufferGeometry } from 'three';
import { PointMaterial } from '@react-three/drei';

/**
 * Particle system component
 * Floating data fragments with randomized motion
 * Performance monitored - auto-disables on slow devices
 */
export default function Particles() {
  const ref = useRef<BufferGeometry>(null);
  const particleCount = 50;

  // Generate random particle positions
  const [positions, speeds] = useMemo(() => {
    const positions = new Float32Array(particleCount * 3);
    const speeds = new Float32Array(particleCount);

    for (let i = 0; i < particleCount; i++) {
      positions[i * 3] = (Math.random() - 0.5) * 20; // x
      positions[i * 3 + 1] = (Math.random() - 0.5) * 20; // y
      positions[i * 3 + 2] = (Math.random() - 0.5) * 10 - 5; // z
      speeds[i] = 0.5 + Math.random() * 1.5; // Random speed 0.5-2
    }

    return [positions, speeds];
  }, []);

  useFrame(() => {
    if (!ref.current) return;

    const positionsArray = ref.current.attributes.position.array as Float32Array;

    for (let i = 0; i < particleCount; i++) {
      // Float upward
      positionsArray[i * 3 + 1] += speeds[i] * 0.01;

      // Reset if too high
      if (positionsArray[i * 3 + 1] > 10) {
        positionsArray[i * 3 + 1] = -10;
      }
    }

    ref.current.attributes.position.needsUpdate = true;
  });

  return (
    <points ref={ref as unknown as React.RefObject<THREE.Points>}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={particleCount}
          array={positions}
          itemSize={3}
        />
      </bufferGeometry>
      <PointMaterial
        transparent
        color="#00F0FF"
        size={0.05}
        sizeAttenuation
        depthWrite={false}
      />
    </points>
  );
}

