import { metadata } from '@/app/layout';
import { motion } from 'framer-motion';
import Link from 'next/link';

export const metadata = {
  title: 'Blog | Aryaniya PS',
  description: 'Technical articles, tutorials, and thoughts on software engineering',
};

// Sample blog posts - would be loaded from MDX files in production
const blogPosts = [
  {
    slug: 'graphql-subscriptions-realtime',
    title: 'GraphQL Subscriptions: Real-time Updates Made Simple',
    excerpt: 'Learn how to implement real-time features in GraphQL using subscriptions, WebSockets, and React',
    date: '2024-03-15',
    tags: ['GraphQL', 'React', 'WebSockets'],
    readTime: '8 min read',
  },
  {
    slug: 'fastapi-best-practices',
    title: 'Building Production APIs with FastAPI',
    excerpt: 'A comprehensive guide to building scalable, production-ready APIs with Python and FastAPI',
    date: '2024-02-28',
    tags: ['Python', 'FastAPI', 'API Design'],
    readTime: '12 min read',
  },
  {
    slug: 'relay-vs-apollo',
    title: 'Relay vs Apollo: Choosing the Right GraphQL Client',
    excerpt: 'An in-depth comparison of Relay and Apollo Client for GraphQL applications',
    date: '2024-01-10',
    tags: ['GraphQL', 'Relay', 'Apollo', 'React'],
    readTime: '10 min read',
  },
];

export default function BlogPage() {
  return (
    <div className="min-h-screen bg-holo-bg py-20">
      <div className="fixed inset-0 opacity-10" style={{
        backgroundImage: `
          linear-gradient(rgba(0, 212, 255, 0.05) 1px, transparent 1px),
          linear-gradient(90deg, rgba(0, 212, 255, 0.05) 1px, transparent 1px)
        `,
        backgroundSize: '50px 50px',
      }} />

      <div className="relative z-10 container mx-auto px-6 max-w-4xl">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="text-center mb-16"
        >
          <h1 className="text-5xl md:text-6xl font-heading mb-4 text-gradient-holographic">
            Blog
          </h1>
          <p className="text-xl text-holo-text opacity-80">
            Technical deep-dives and engineering thoughts
          </p>
        </motion.div>

        {/* Blog Posts Grid */}
        <div className="space-y-8">
          {blogPosts.map((post, index) => (
            <motion.article
              key={post.slug}
              initial={{ opacity: 0, y: 50 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{
                duration: 0.6,
                delay: index * 0.1,
              }}
            >
              <Link href={`/blog/${post.slug}`}>
                <motion.div
                  className="bg-holo-bg/50 backdrop-blur border border-holo-blue-primary/30 rounded-lg p-8 hover:border-holo-blue-primary/60 transition-colors group"
                  whileHover={{ y: -4, boxShadow: '0 10px 40px rgba(0, 212, 255, 0.2)' }}
                >
                  {/* Metadata */}
                  <div className="flex flex-wrap items-center gap-4 mb-4 text-sm">
                    <time className="text-holo-green mono">{post.date}</time>
                    <span className="text-holo-coral">•</span>
                    <span className="text-holo-teal mono">{post.readTime}</span>
                  </div>

                  {/* Title */}
                  <h2 className="text-2xl md:text-3xl font-heading mb-3 text-holo-text group-hover:text-holo-blue-primary transition-colors">
                    {post.title}
                  </h2>

                  {/* Excerpt */}
                  <p className="text-holo-text opacity-80 mb-4 line-clamp-2">
                    {post.excerpt}
                  </p>

                  {/* Tags */}
                  <div className="flex flex-wrap gap-2">
                    {post.tags.map((tag) => (
                      <span
                        key={tag}
                        className="px-3 py-1 bg-holo-blue-primary/10 text-holo-blue-primary text-sm mono rounded"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                </motion.div>
              </Link>
            </motion.article>
          ))}
        </div>

        {/* More posts coming */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5 }}
          className="mt-16 text-center"
        >
          <div className="inline-flex items-center gap-2 px-6 py-3 border border-holo-teal/30 rounded-lg">
            <div className="w-2 h-2 bg-holo-teal rounded-full animate-pulse" />
            <span className="mono text-sm text-holo-teal">More articles coming soon</span>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

