  --text-h1: 48px;
  --text-h1-line: 56px;
  --text-h2: 36px;
  --text-h2-line: 44px;
  --text-h3: 24px;
  --text-h3-line: 32px;
  --text-body: 16px;
  --text-body-line: 24px;
  --text-small: 14px;
  --text-small-line: 20px;

  /* Letter Spacing */
  --tracking-tight: -0.02em;
  --tracking-normal: 0;
  --tracking-wide: 0.05em;

  /* Gradients */
  --gradient-holographic: linear-gradient(135deg, #00D4FF 0%, #00F0FF 50%, #0A0E17 100%);
  --gradient-arc-reactor: radial-gradient(circle, #00D4FF 0%, #FF6B00 100%);
  --gradient-playful: linear-gradient(135deg, #FF6B9D 0%, #B794F6 100%);
}

/* Mobile Typography */
@media (max-width: 768px) {
  :root {
    --text-h1: 32px;
    --text-h1-line: 40px;
    --text-h2: 28px;
    --text-h2-line: 36px;
    --text-h3: 20px;
