toolUseResult.originalFile:
'use client';

import { useRef, useState, useEffect } from 'react';
import { motion, useMotionValue, useSpring, useTransform } from 'framer-motion';

/**
 * Arc Reactor component with mouse parallax effect
 * Glowing pulsing orb that follows cursor with 100ms delay
 */
export default function ArcReactor() {
  const ref = useRef<HTMLDivElement>(null);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const springConfig = { damping: 25, stiffness: 300 };
  const springX = useSpring(x, springConfig);
  const springY = useSpring(y, springConfig);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!ref.current) return;

      const rect = ref.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      // Calculate offset from center (max 20px)
      const offsetX = Math.max(-20, Math.min(20, (e.clientX - centerX) * 0.1));
      const offsetY = Math.max(-20, Math.min(20, (e.clientY - centerY) * 0.1));

      setMousePosition({ x: offsetX, y: offsetY });
      x.set(offsetX);
      y.set(offsetY);
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [x, y]);

  return (
    <motion.div
      ref={ref}
      className="relative"
      style={{
        x: springX,
        y: springY,
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Main reactor glow */}
      <motion.div
        className="relative"
        animate={{
          scale: isHovered ? [1, 1.05, 1] : [0.95, 1.05, 0.95],
          opacity: isHovered ? 1 : 0.9,
        }}
        transition={{
          duration: 2,
          repeat: Infinity,
          ease: 'easeInOut',
        }}
      >
        {/* Outer glow ring */}
        <div className="absolute inset-0 rounded-full bg-gradient-radial from-holo-blue-primary via-holo-blue-secondary to-holo-warning blur-xl opacity-60" />

        {/* Core reactor */}
        <div className="relative w-32 h-32 md:w-40 md:h-40 rounded-full bg-gradient-radial from-holo-blue-primary to-holo-warning glow-holographic">
          {/* Inner detail rings */}
          <div className="absolute inset-4 rounded-full border-2 border-holo-blue-primary/30" />
          <div className="absolute inset-8 rounded-full border border-holo-coral/20" />
          <div className="absolute inset-12 rounded-full bg-holo-blue-primary/50" />
        </div>

        {/* Particle effects around reactor */}
        <div className="absolute -inset-8 pointer-events-none">
          {[...Array(8)].map((_, i) => (
            <motion.div
              key={i}
              className="absolute w-1 h-1 bg-holo-teal rounded-full"
              style={{
                left: '50%',
                top: '50%',
              }}
              animate={{
                x: [0, Math.cos((i * Math.PI * 2) / 8) * 60],
                y: [0, Math.sin((i * Math.PI * 2) / 8) * 60],
                opacity: [1, 0],
                scale: [1, 0],
              }}
              transition={{
                duration: 3,
                repeat: Infinity,
                delay: i * 0.2,
                ease: 'easeOut',
              }}
            />
          ))}
        </div>
      </motion.div>

      {/* Data readout */}
      <div className="absolute -bottom-16 left-1/2 -translate-x-1/2 mono text-xs text-holo-green opacity-70">
        REACTOR ONLINE
      </div>
    </motion.div>
  );
}

