                <motion.div
                  key={stat.label}
                  whileHover={{ scale: 1.05 }}
                  className="border border-holo-blue-primary/20 rounded-lg p-4 text-center"
                >
                  <div className={`text-3xl font-heading mb-2 text-${stat.color}`}>
                    {stat.value}
                  </div>
                  <div className="text-sm opacity-70">{stat.label}</div>
                </motion.div>
              ))}
