export function isMobile(): boolean {
  if (typeof window === 'undefined') return false;
  const width = window.innerWidth;
  const userAgent = navigator.userAgent || navigator.vendor || (window as any).opera;
  return width < 768 || /Mobi|Android/i.test(userAgent);
}

export function isWebGLSupported(): boolean {
  if (typeof window === 'undefined') return false;
  const canvas = document.createElement('canvas');
  const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
  return gl !== null;
}
```

### **utils/performance.ts**
- **Why:** Performance monitoring for adaptive WebGL
```typescript
let slowFrameCount = 0;
const DISABLE_THRESHOLD = 20; // ms
const CONSECUTIVE_SLOW_FRAMES = 3;

export function measureFrameTime(delta: number): { shouldDisableParticles: boolean } {
  const frameTimeMs = delta * 1000;
  if (frameTimeMs > DISABLE_THRESHOLD) {
    slowFrameCount++;
    if (slowFrameCount >= CONSECUTIVE_SLOW_FRAMES) {
      return { shouldDisableParticles: true };
    }
  }
  return { shouldDisableParticles: false };
