const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const SCREENSHOTS_DIR = path.join(__dirname, '../test-results/screenshots');
fs.mkdirSync(SCREENSHOTS_DIR, { recursive: true });

const pages = [
  { url: '/', name: 'homepage-desktop', viewport: { width: 1920, height: 1080 } },
  { url: '/', name: 'homepage-mobile', viewport: { width: 375, height: 667 } },
  { url: '/projects', name: 'projects-desktop', viewport: { width: 1920, height: 1080 } },
  { url: '/about', name: 'about-desktop', viewport: { width: 1920, height: 1080 } },
  { url: '/blog', name: 'blog-desktop', viewport: { width: 1920, height: 1080 } },
  { url: '/contact', name: 'contact-desktop', viewport: { width: 1920, height: 1080 } },
];

async function captureScreenshots() {
  const browser = await chromium.launch();
  const context = await browser.newContext();
  const page = await context.newPage();

  console.log('Capturing screenshots...');

  for (const { url, name, viewport } of pages) {
    console.log(`  Capturing ${name}...`);

    await page.setViewportSize(viewport);
    await page.goto(`http://localhost:3001${url}`, { waitUntil: 'networkidle', timeout: 30000 });

    // Wait a bit for WebGL/animations
    await page.waitForTimeout(name === 'homepage-desktop' ? 3000 : 1000);

    const screenshotPath = path.join(SCREENSHOTS_DIR, `${name}.png`);
    await page.screenshot({ path: screenshotPath, fullPage: true });
    console.log(`    ✓ Saved to ${screenshotPath}`);
  }

  // Capture modal
  console.log('  Capturing quick-pitch-modal...');
  await page.setViewportSize({ width: 1920, height: 1080 });
  await page.goto('http://localhost:3001/', { waitUntil: 'networkidle' });
  await page.waitForTimeout(2000);
  await page.click('button:has-text("Quick Pitch")');
  await page.waitForTimeout(500);
  await page.screenshot({ path: path.join(SCREENSHOTS_DIR, 'quick-pitch-modal.png') });
  console.log('    ✓ Saved quick-pitch-modal.png');

  await browser.close();
  console.log('\nAll screenshots captured!');
}

captureScreenshots().catch(console.error);

