const { chromium } = require('playwright');

async function debugRendering() {
  const browser = await chromium.launch();
  const context = await browser.newContext();
  const page = await context.newPage();

  // Capture console logs
  page.on('console', msg => {
    console.log(`BROWSER: ${msg.text()}`);
  });

  // Capture errors
  page.on('pageerror', error => {
    console.error(`BROWSER ERROR: ${error.message}`);
  });

  console.log('Loading homepage...\n');
  await page.setViewportSize({ width: 1920, height: 1080 });
  await page.goto('http://localhost:3001/', { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);

  // Check what's actually rendered
  const pageInfo = await page.evaluate(() => {
    return {
      userAgent: navigator.userAgent,
      windowWidth: window.innerWidth,
      hasReact: typeof React !== 'undefined',
      hasReactDOM: typeof ReactDOM !== 'undefined',
      bodyHTML: document.body.innerHTML.substring(0, 500),
      canvasElements: Array.from(document.querySelectorAll('canvas')).map(c => ({
        width: c.width,
        height: c.height,
        hasWebGLContext: !!c.getContext('webgl2') || !!c.getContext('webgl'),
      })),
    };
  });

  console.log('\n=== PAGE INFO ===');
  console.log('Window width:', pageInfo.windowWidth);
  console.log('User agent:', pageInfo.userAgent);
  console.log('Canvas elements:', pageInfo.canvasElements.length);
  console.log('\nBody HTML (first 500 chars):');
  console.log(pageInfo.bodyHTML);

  // Check if deviceDetection is working
  const deviceCheck = await page.evaluate(() => {
    // Try to access the module
    try {
      const utils = require('@/utils/deviceDetection');
      return {
        canRequire: true,
        deviceInfo: utils.getDeviceInfo(),
      };
    } catch (e) {
      return {
        canRequire: false,
        error: e.message,
      };
    }
  });

  console.log('\n=== DEVICE DETECTION ===');
  console.log(JSON.stringify(deviceCheck, null, 2));

  await browser.close();
}

debugRendering().catch(console.error);

