import { getDeviceInfo } from '@/utils/deviceDetection';
import Hero from '@/components/Hero';

/**
 * Conditional rendering for adaptive experiences
 * Desktop: Full WebGL experience
 * Mobile: CSS-only fallback
 */
export default function HomePage() {
  const device = getDeviceInfo();

  // On server, always render shell
  // Client component will conditionally load WebGL
  return <Hero isWebGLSupported={device.isWebGLSupported && !device.isMobile} />;
}

content.thinking:
The issue is clear now! The `getDeviceInfo()` is being called in a SERVER component (app/page.tsx has no 'use client' directive). Server components run on the server where `typeof window === 'undefined'`, so `isWebGLSupported` will return false and `isMobile` will return false.

Looking back at the deviceDetection code:
```typescript
export function getDeviceInfo(): DeviceInfo {
  if (typeof window === 'undefined') {
    return {
      isMobile: false,
      isWebGLSupported: false,  // <-- This!
      hardwareConcurrency: 4,
      deviceMemory: undefined,
    };
  }
  // ...
}
```

So the Hero component is being passed `isWebGLSupported={false}` from the server, which means it will ALWAYS render the MobileHero (CSS-only) version, even on desktop!

The fix is to make the page component a CLIENT component so it can detect the actual device capabilities. Or, we need to defer the device detection to client-side only in the Hero component itself.

Let me fix this by making the page a client component OR by moving the device detection into the Hero component.

The better approach is to move device detection into the Hero component (which is already a client component).

