'use client';

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import dynamic from 'next/dynamic';
import { getDeviceInfo } from '@/utils/deviceDetection';

// Dynamic import for WebGL components (desktop only)
const DesktopHero = dynamic(() => import('./DesktopHero'), {
  ssr: false,
  loading: () => (
    <div className="min-h-screen flex items-center justify-center bg-holo-bg">
      <div className="animate-pulse text-holo-blue-primary text-2xl font-heading">
        Loading J.A.R.V.I.S. interface...
      </div>
    </div>
  ),
});

// Static CSS-only hero (mobile/fallback)
function MobileHero() {
  const [showModal, setShowModal] = useState(false);

  return (
    <div className="min-h-screen bg-holo-bg relative overflow-hidden">
      {/* Animated background gradient */}
      <motion.div
        className="absolute inset-0 bg-gradient-to-br from-holo-bg via-[#0a1525] to-holo-bg opacity-50"
        animate={{
          backgroundPosition: ['0% 0%', '100% 100%', '0% 0%'],
        }}
        transition={{
          duration: 20,
          repeat: Infinity,
          ease: 'linear',
        }}
        style={{
          backgroundSize: '200% 200%',
        }}
      />

      {/* Grid overlay */}
      <div className="absolute inset-0 opacity-10" style={{
        backgroundImage: `
          linear-gradient(rgba(0, 212, 255, 0.1) 1px, transparent 1px),
          linear-gradient(90deg, rgba(0, 212, 255, 0.1) 1px, transparent 1px)
        `,
        backgroundSize: '50px 50px',
      }} />

      {/* Content */}
      <div className="relative z-10 container mx-auto px-6 py-12">
        <div className="max-w-4xl mx-auto text-center">
          {/* Arc Reactor */}
          <div className="mb-8 flex justify-center">
            <div className="relative w-24 h-24 md:w-32 md:h-32">
              <div className="absolute inset-0 rounded-full bg-gradient-radial from-holo-blue-primary to-holo-warning animate-pulse" />
              <div className="absolute inset-2 rounded-full border-2 border-holo-blue-primary/50" />
              <div className="absolute inset-6 rounded-full bg-holo-bg" />
              <div className="absolute inset-10 rounded-full bg-gradient-radial from-holo-blue-primary/80 to-holo-warning animate-pulse" />
            </div>
          </div>

          {/* Headline with glitch effect */}
          <motion.h1
            className="text-5xl md:text-6xl font-heading mb-6 text-gradient-holographic"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            Aryan Iyappan
          </motion.h1>

          <motion.p
            className="text-xl md:text-2xl text-holo-text mb-12"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3, duration: 0.8 }}
          >
            Technical Founder building AI-powered developer tools
          </motion.p>

          {/* Dual CTAs */}
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <button
              onClick={() => setShowModal(true)}
              className="px-8 py-4 bg-holo-blue-primary text-holo-bg font-heading font-bold rounded-lg hover:bg-holo-blue-secondary transition-colors"
            >
              Quick Pitch
            </button>
            <button
              onClick={() => (window.location.href = '#projects')}
              className="px-8 py-4 border-2 border-holo-blue-primary text-holo-blue-primary font-heading font-bold rounded-lg hover:bg-holo-blue-primary/10 transition-colors"
            >
              Deep Dive
            </button>
          </div>
        </div>
      </div>

      {/* Quick Pitch Modal */}
      {showModal && (
        <div
          className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6"
          onClick={() => setShowModal(false)}
        >
          <div
            className="bg-holo-bg border border-holo-blue-primary/30 rounded-lg max-w-2xl w-full p-8"
            onClick={(e) => e.stopPropagation()}
          >
            <h2 className="text-3xl font-heading mb-4 text-gradient-holographic">What I&apos;m Building</h2>

            <div className="space-y-4 text-holo-text">
              <p className="text-lg">
                I&apos;m building AI-powered developer tools that 10x engineering velocity.
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 my-6">
                <div className="border border-holo-coral/30 rounded-lg p-4">
                  <div className="text-holo-coral font-mono text-sm mb-1">Open Source</div>
                  <div className="text-2xl font-heading">500+</div>
                  <div className="text-sm text-gray-400">GitHub stars</div>
                </div>

                <div className="border border-holo-teal/30 rounded-lg p-4">
                  <div className="text-holo-teal font-mono text-sm mb-1">Experience</div>
                  <div className="text-2xl font-heading">5 years</div>
                  <div className="text-sm text-gray-400">Full-stack dev</div>
                </div>
              </div>

              <p className="text-sm text-gray-400">
                Ship production code at VC-startup speed. Deep expertise in GraphQL,
                FastAPI, and modern React.
              </p>
            </div>

            <button
              onClick={() => {
                setShowModal(false);
                window.location.href = '#projects';
              }}
              className="mt-6 w-full px-6 py-3 bg-gradient-playful text-white font-heading font-bold rounded-lg hover:opacity-90 transition-opacity"
            >
              Want more detail?
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default function Hero() {
  const [isClient, setIsClient] = useState(false);
  const [deviceInfo, setDeviceInfo] = useState({ isWebGLSupported: false, isMobile: true });

  useEffect(() => {
    // Only run on client
    setIsClient(true);
    const device = getDeviceInfo();
    setDeviceInfo(device);
  }, []);

  // Show loading during SSR to prevent flash
  if (!isClient) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-holo-bg">
        <div className="animate-pulse text-holo-blue-primary text-2xl font-heading">
          Initializing...
        </div>
      </div>
    );
  }

  // Conditionally render based on device capabilities
  if (deviceInfo.isWebGLSupported && !deviceInfo.isMobile) {
    return <DesktopHero />;
  }

  return <MobileHero />;
}

