const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const OUTPUT_FILE = path.join(__dirname, '../test-results/webgl-verification.json');

async function verifyWebGL() {
  const browser = await chromium.launch();
  const context = await browser.newContext();
  const page = await context.newPage();

  console.log('Verifying WebGL and holographic graphics...\n');

  const results = {
    timestamp: new Date().toISOString(),
    pages: [],
  };

  // Test homepage (desktop)
  console.log('Testing homepage (desktop viewport)...');
  await page.setViewportSize({ width: 1920, height: 1080 });
  await page.goto('http://localhost:3000/', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(3000); // Wait for WebGL to initialize

  const homepageCheck = {
    url: '/',
    viewport: '1920x1080 (desktop)',
    hasCanvas: false,
    canvasCount: 0,
    hasThreeJS: false,
    hasHolographicText: false,
    hasQuickPitchButton: false,
    errors: [],
  };

  try {
    // Check for canvas elements
    const canvasCount = await page.locator('canvas').count();
    homepageCheck.canvasCount = canvasCount;
    homepageCheck.hasCanvas = canvasCount > 0;

    // Check if Three.js is loaded
    const hasThreeJS = await page.evaluate(() => {
      return typeof window.THREE !== 'undefined' ||
             typeof window.ReactThreeFiber !== 'undefined';
    });
    homepageCheck.hasThreeJS = hasThreeJS;

    // Check for holographic elements
    const hasText = await page.locator('text=Aryan Iyappan').count() > 0;
    homepageCheck.hasHolographicText = hasText;

    // Check for Quick Pitch button
    const hasButton = await page.locator('button:has-text("Quick Pitch")').count() > 0;
    homepageCheck.hasQuickPitchButton = hasButton;

    // Get WebGL context info
    const webglInfo = await page.evaluate(() => {
      const canvas = document.querySelector('canvas');
      if (!canvas) return { error: 'No canvas found' };

      const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
      if (!gl) return { error: 'No WebGL context' };

      return {
        webglVersion: gl.getParameter(gl.VERSION),
        renderer: gl.getParameter(gl.RENDERER),
        vendor: gl.getParameter(gl.VENDOR),
      };
    });
    homepageCheck.webglInfo = webglInfo;

  } catch (error) {
    homepageCheck.errors.push(error.message);
  }

  results.pages.push(homepageCheck);

  // Test homepage (mobile)
  console.log('Testing homepage (mobile viewport)...');
  await page.setViewportSize({ width: 375, height: 667 });
  await page.goto('http://localhost:3001/', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(1000);

  const mobileCheck = {
    url: '/',
    viewport: '375x667 (mobile)',
    hasCanvas: false,
    canvasCount: 0,
    hasHolographicText: false,
    usesCSSFallback: false,
    errors: [],
  };

  try {
    const canvasCount = await page.locator('canvas').count();
    mobileCheck.canvasCount = canvasCount;
    mobileCheck.hasCanvas = canvasCount > 0;

    const hasText = await page.locator('text=Aryan Iyappan').count() > 0;
    mobileCheck.hasHolographicText = hasText;

    // Check for CSS fallback elements
    const hasArcReactor = await page.locator('[class*="arc"]').or(page.locator('[class*="reactor"]')).count() > 0;
    mobileCheck.usesCSSFallback = hasArcReactor;

  } catch (error) {
    mobileCheck.errors.push(error.message);
  }

  results.pages.push(mobileCheck);

  // Save results
  fs.writeFileSync(OUTPUT_FILE, JSON.stringify(results, null, 2));
  console.log(`\nResults saved to ${OUTPUT_FILE}\n`);

  // Print summary
  console.log('=== VERIFICATION SUMMARY ===\n');
  results.pages.forEach((page, idx) => {
    console.log(`Page ${idx + 1}: ${page.url} (${page.viewport})`);
    console.log(`  Canvas elements: ${page.canvasCount}`);
    console.log(`  WebGL present: ${page.hasCanvas || page.hasThreeJS || false}`);
    console.log(`  Holographic text: ${page.hasHolographicText || false}`);
    if (page.errors.length > 0) {
      console.log(`  Errors: ${page.errors.join(', ')}`);
    }
    console.log('');
  });

  await browser.close();

  // Return exit code based on success
  const homepageSuccess = homepageCheck.hasCanvas && homepageCheck.hasHolographicText;
  return homepageSuccess ? 0 : 1;
}

verifyWebGL()
  .then((code) => {
    process.exit(code);
  })
  .catch((error) => {
    console.error('Error:', error);
    process.exit(1);
  });

