const { chromium } = require('playwright');

async function simpleCheck() {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  // Capture console
  page.on('console', msg => console.log(`BROWSER: ${msg.text()}`));
  page.on('pageerror', error => console.error(`BROWSER ERROR: ${error.message}`));

  console.log('Loading page...\n');
  await page.setViewportSize({ width: 1920, height: 1080 });
  await page.goto('http://localhost:3000/', { waitUntil: 'networkidle', timeout: 30000 });

  // Wait for React to mount
  await page.waitForTimeout(5000);

  // Check page state
  const pageData = await page.evaluate(() => {
    const canvas = document.querySelector('canvas');
    return {
      title: document.title,
      hasCanvas: !!canvas,
      canvasCount: document.querySelectorAll('canvas').length,
      bodyClass: document.body.className,
      hasReact: typeof window.React !== 'undefined',
      hasThreeJS: typeof window.THREE !== 'undefined',
      // Check for holographic text
      hasHolographicText: document.body.textContent.includes('Aryan Iyappan'),
      // Get error messages if any
      errorElements: Array.from(document.querySelectorAll('[class*="error"]')).map(el => el.textContent),
    };
  });

  console.log('\n=== PAGE CHECK RESULTS ===\n');
  console.log(JSON.stringify(pageData, null, 2));

  await browser.close();
}

simpleCheck().catch(console.error);

